import React, { useState } from 'react';
import axios from 'axios';
import FlightMap from '../components/FlightMap';
import './Dashboard.css';

export default function Dashboard() {
  const [query, setQuery] = useState('');
  const [flights, setFlights] = useState([]);
  const [selected, setSelected] = useState(null);

  const fetchFlights = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/flights/${query}`
      );
      setFlights(res.data);
      setSelected(null);
    } catch (err) {
      console.error(err);
      alert('Error fetching flight data');
    }
  };

  return (
    <div className="container">
      <h1 className="title">✈️ Flight Tracker Pro</h1>

      <div className="search-box">
        <input
          placeholder="Enter Callsign (e.g. QTR8964)"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
        />
        <button onClick={fetchFlights}>Track</button>
      </div>

      <FlightMap flights={flights} selected={selected} />

      <div className="cards">
        {flights.map((f, i) => (
          <div
            key={i}
            className={`card ${selected === f ? 'active' : ''}`}
            onClick={() => setSelected(f)}
          >
            <h3>{f.callsign}</h3>
            <p>{f.country}</p>
          </div>
        ))}
      </div>

      {selected && (
        <div className="details">
          <h2>✈️ {selected.callsign}</h2>
          <p><b>Country:</b> {selected.country}</p>
          <p><b>Latitude:</b> {selected.latitude}</p>
          <p><b>Longitude:</b> {selected.longitude}</p>
          <p><b>Altitude:</b> {Math.round(selected.altitude)}</p>
          <p><b>Velocity:</b> {Math.round(selected.velocity)}</p>
          <p><b>ICAO24:</b> {selected.icao24}</p>
        </div>
      )}
    </div>
  );
}
